from dataclasses import dataclass, field
from typing import Any


@dataclass
class ActionResult:
    """
    The outcome of executing one action.
    Always returned — even on failure — so the agent loop
    has a consistent interface for every action type.
    """

    success: bool
    output: Any = None              # tool output, file contents, API response
    error: str | None = None        # error message if success=False
    duration_ms: float = 0.0        # wall-clock time for the action
    action_name: str = ""
    metadata: dict = field(default_factory=dict)

    @classmethod
    def ok(cls, output: Any, action_name: str = "", **meta) -> "ActionResult":
        return cls(success=True, output=output, action_name=action_name, metadata=meta)

    @classmethod
    def fail(cls, error: str, action_name: str = "", **meta) -> "ActionResult":
        return cls(success=False, error=error, action_name=action_name, metadata=meta)


# Examples
r1 = ActionResult.ok({"temp": 22.3}, action_name="read_sensor")
r2 = ActionResult.fail("connection timeout", action_name="read_sensor")

print(r1.success, r1.output)   # True, {"temp": 22.3}
print(r2.success, r2.error)    # False, "connection timeout"

import time
from dataclasses import dataclass
from typing import Callable


@dataclass
class ActionExecutor:
    """
    Wraps a callable tool with validation, timeout, and error capture.
    Keeps execution concerns out of the agent's reasoning layer.
    """

    name: str
    fn: Callable
    timeout_s: float = 30.0
    allowed_params: frozenset[str] = frozenset()

    def execute(self, params: dict) -> ActionResult:
        """Validate params, run with timeout, capture result or error."""
        # 1. Validate parameters
        if self.allowed_params:
            unknown = set(params) - self.allowed_params
            if unknown:
                return ActionResult.fail(
                    f"Unknown params: {unknown}",
                    action_name=self.name,
                )

        # 2. Execute with timing
        t0 = time.monotonic()
        try:
            import signal

            def _timeout_handler(signum, frame):
                raise TimeoutError(f"{self.name} exceeded {self.timeout_s}s")

            # Note: signal-based timeout only works on the main thread
            signal.signal(signal.SIGALRM, _timeout_handler)
            signal.alarm(int(self.timeout_s))
            try:
                output = self.fn(**params)
            finally:
                signal.alarm(0)   # cancel the alarm

            duration_ms = (time.monotonic() - t0) * 1000
            return ActionResult.ok(
                output, action_name=self.name,
                duration_ms=duration_ms,
            )
        except Exception as exc:
            duration_ms = (time.monotonic() - t0) * 1000
            return ActionResult.fail(
                str(exc), action_name=self.name,
                duration_ms=duration_ms,
            )


def read_temperature(location: str) -> dict:
    return {"temperature_c": 22.3, "location": location}


executor = ActionExecutor(
    name="read_temperature",
    fn=read_temperature,
    timeout_s=5.0,
    allowed_params=frozenset(["location"]),
)

result = executor.execute({"location": "office"})
print(result.success, result.output)   # True, {"temperature_c": 22.3, ...}

bad = executor.execute({"loc": "office"})  # wrong param name
print(bad.success, bad.error)              # False, "Unknown params: {'loc'}"

from dataclasses import dataclass, field


@dataclass
class ToolRegistry:
    """
    Maps tool names to ActionExecutor instances.
    The agent dispatches tool calls through this registry.
    """

    _tools: dict[str, ActionExecutor] = field(default_factory=dict)

    def register(self, executor: ActionExecutor) -> None:
        self._tools[executor.name] = executor

    def dispatch(self, tool_name: str, params: dict) -> ActionResult:
        """Look up and execute the named tool."""
        executor = self._tools.get(tool_name)
        if executor is None:
            return ActionResult.fail(
                f"Unknown tool: {tool_name!r}",
                action_name=tool_name,
            )
        return executor.execute(params)

    def available_tools(self) -> list[str]:
        return list(self._tools.keys())


registry = ToolRegistry()
registry.register(ActionExecutor("read_temperature", read_temperature, timeout_s=5.0))
registry.register(ActionExecutor("send_alert", lambda msg: print(f"ALERT: {msg}"), timeout_s=2.0))

result = registry.dispatch("read_temperature", {"location": "warehouse"})
print(result.output)

missing = registry.dispatch("fly_drone", {})
print(missing.error)  # "Unknown tool: 'fly_drone'"

from abc import ABC, abstractmethod


class Action(ABC):
    """Base class for all action types."""

    @abstractmethod
    def execute(self) -> ActionResult:
        ...


class ToolCallAction(Action):
    """Invoke an external tool or API."""

    def __init__(self, registry: ToolRegistry, tool_name: str, params: dict):
        self._registry = registry
        self._tool = tool_name
        self._params = params

    def execute(self) -> ActionResult:
        return self._registry.dispatch(self._tool, self._params)


class MessageAction(Action):
    """Send a text response to the user or system."""

    def __init__(self, recipient: str, text: str):
        self._recipient = recipient
        self._text = text

    def execute(self) -> ActionResult:
        # In a real system, deliver to message bus / UI layer
        print(f"[{self._recipient}]: {self._text}")
        return ActionResult.ok({"delivered": True}, action_name="message")


class WaitAction(Action):
    """Pause execution until a condition is met or a timeout expires."""

    def __init__(self, condition_met: bool, reason: str = ""):
        self._ready = condition_met
        self._reason = reason

    def execute(self) -> ActionResult:
        if self._ready:
            return ActionResult.ok(None, action_name="wait")
        return ActionResult.fail(
            f"Waiting: {self._reason}", action_name="wait"
        )

import anthropic
import json


def run_agent_action_loop(
    goal: str,
    registry: ToolRegistry,
    tool_schemas: list[dict],
    max_turns: int = 10,
) -> str:
    """
    Agent loop that dispatches tool calls through the registry.
    Each ActionResult is returned to the model as an observation.
    """
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": goal}]

    for _ in range(max_turns):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=tool_schemas,
            messages=messages,
        )

        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next(
                (b.text for b in response.content if hasattr(b, "text")), ""
            )

        # Dispatch each tool call through the registry
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = registry.dispatch(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(
                        result.output if result.success
                        else {"error": result.error}
                    ),
                })

        if tool_results:
            messages.append({"role": "user", "content": tool_results})

    return "max_turns reached"

import time
from dataclasses import dataclass


@dataclass
class RetryPolicy:
    max_attempts: int = 3
    base_delay_s: float = 1.0
    backoff_factor: float = 2.0
    retryable_errors: frozenset[str] = frozenset(["timeout", "connection", "rate_limit"])

    def should_retry(self, result: ActionResult, attempt: int) -> bool:
        if result.success:
            return False
        if attempt >= self.max_attempts:
            return False
        # Only retry transient errors
        error_lower = (result.error or "").lower()
        return any(e in error_lower for e in self.retryable_errors)

    def delay_for(self, attempt: int) -> float:
        return self.base_delay_s * (self.backoff_factor ** (attempt - 1))


def execute_with_retry(
    executor: ActionExecutor,
    params: dict,
    policy: RetryPolicy | None = None,
) -> ActionResult:
    """Execute an action; retry on transient failures with exponential backoff."""
    policy = policy or RetryPolicy()
    attempt = 0
    result = ActionResult.fail("not started")

    while attempt < policy.max_attempts:
        attempt += 1
        result = executor.execute(params)
        if not policy.should_retry(result, attempt):
            break
        delay = policy.delay_for(attempt)
        time.sleep(delay)

    return result


# Network call that occasionally times out — retry up to 3 times
policy = RetryPolicy(max_attempts=3, base_delay_s=0.5, backoff_factor=2.0)
result = execute_with_retry(executor, {"location": "office"}, policy)
